SELECT DISTINCT S.GENERO FROM CARGO C JOIN SERVIDOR S ON S.PK_SIAPE = C.FK_SIAPE WHERE C.SIGLA_CAMPUS = 'GYN' AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%sociolog%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG, '')) LIKE '%sociolog%') AND (LOWER(COALESCE(C.FUNCAO, '')) LIKE '%substitu%' OR LOWER(COALESCE(C.ATIVIDADE, '')) LIKE '%substitu%') AND C.DATA_ENTRADA <= DATE('now') AND COALESCE(C.DATA_SAIDA, DATE('now')) >= (DATE('now', '-5 years'))